import type { ChartInteractionModes } from './zoom.js';
import type { InteractionMode } from '../components/interactions-overlay/types.js';
/**
 * Represents the mode for displaying a menu.
 * @internal
 */
export type MenuTrigger = 'menu';
/**
 * Represents the mode for collapsing the toolbar.
 * @internal
 */
export type Collapse = 'collapse';
/**
 * Union type representing all possible toolbar interaction modes.
 * @internal
 */
export type ToolbarInteractionModes = InteractionMode | ChartInteractionModes | MenuTrigger | Collapse;
